<div class="section-content">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in your browser</div>
                </label>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">Muted Channels</div>
        <div class="card-body">
            @if (allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@saving">
        @if (saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool saving;
    private string? statusMessage;

    // Available channels for the mute list
    private readonly List<string> allChannels = ["general", "announcements", "engineering", "design", "marketing", "support"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !saving)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                emailNotifications, pushNotifications, weeklyDigest,
                mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            statusMessage = "Notification preferences saved!";
        }
        finally
        {
            saving = false;
        }
    }
}

@namespace sv_5117f83b204c47e0925b9d7c1f6f89c0.Components.Settings

<div class="section-content">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="HandlePasswordChange" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="text-muted small">Add an extra layer of security to your account</div>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" @bind="twoFactorEnabled" />
                    </div>
                </div>
            </div>
        </div>
    </div>

    @if (Security?.LastPasswordChange is not null)
    {
        <p class="text-muted small mb-4">
            Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    <div class="card mb-4">
        <div class="card-header">Active Sessions</div>
        <div class="card-body p-0">
            @if (Security?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in Security.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (session != Security.Sessions[0])
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted p-3 mb-0">No active sessions.</p>
            }
        </div>
    </div>

    <RevokeSessionDialog Visible="showRevokeDialog"
                         DeviceName="@(sessionToRevoke?.Device ?? "")"
                         Revoking="revoking"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool twoFactorEnabled;
    private bool showRevokeDialog;
    private bool revoking;
    private ActiveSession? sessionToRevoke;

    protected override void OnParametersSet()
    {
        if (Security is not null)
        {
            twoFactorEnabled = Security.TwoFactorEnabled;
        }
    }

    private Task HandlePasswordChange((string Current, string New) args)
        => OnChangePassword.InvokeAsync(args);

    private void PromptRevoke(ActiveSession session)
    {
        sessionToRevoke = session;
        showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is null) return;
        revoking = true;
        try
        {
            await OnRevokeSession.InvokeAsync(sessionToRevoke.Id);
            showRevokeDialog = false;
            sessionToRevoke = null;
        }
        finally
        {
            revoking = false;
        }
    }

    private void CancelRevoke()
    {
        showRevokeDialog = false;
        sessionToRevoke = null;
    }
}

@namespace sv_5117f83b204c47e0925b9d7c1f6f89c0.Components.Settings

<div class="section-content">
    <h4 class="mb-4">Appearance</h4>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-header">Theme</div>
                <div class="card-body">
                    @foreach (var opt in themeOptions)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{opt.Value}")"
                                   value="@opt.Value"
                                   checked="@(theme == opt.Value)"
                                   @onchange="() => theme = opt.Value" />
                            <label class="form-check-label" for="@($"theme-{opt.Value}")">@opt.Label</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header">Font Size</div>
                <div class="card-body">
                    @foreach (var opt in fontOptions)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"font-{opt.Value}")"
                                   value="@opt.Value"
                                   checked="@(fontSize == opt.Value)"
                                   @onchange="() => fontSize = opt.Value" />
                            <label class="form-check-label" for="@($"font-{opt.Value}")">@opt.Label</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header">Language</div>
                <div class="card-body">
                    <select class="form-select" @bind="language">
                        @foreach (var lang in languageOptions)
                        {
                            <option value="@lang.Value">@lang.Label</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@saving">
                @if (saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-6">
            <div class="card">
                <div class="card-header">Live Preview</div>
                <div class="card-body preview-area @PreviewThemeClass"
                     style="font-size: @PreviewFontSize; padding: @(compactMode ? "0.5rem" : "1.25rem");">
                    <h5 style="margin-bottom: @(compactMode ? "0.25rem" : "0.75rem")">Preview Heading</h5>
                    <p style="margin-bottom: @(compactMode ? "0.25rem" : "0.75rem")">
                        This is a sample paragraph showing how your selected settings will look.
                        The current theme is <strong>@theme</strong> with <strong>@fontSize</strong> font.
                    </p>
                    <div class="d-flex gap-2" style="margin-bottom: @(compactMode ? "0.25rem" : "0.75rem")">
                        <button class="btn btn-primary btn-sm">Primary</button>
                        <button class="btn btn-outline-secondary btn-sm">Secondary</button>
                    </div>
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" checked disabled />
                        <label class="form-check-label">Sample checkbox</label>
                    </div>
                    <p class="text-muted small mt-2 mb-0">Language: @SelectedLanguageLabel</p>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string theme = "System";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private bool saving;
    private string? statusMessage;

    private static readonly (string Value, string Label)[] themeOptions =
        [("Light", "Light"), ("Dark", "Dark"), ("System", "System")];

    private static readonly (string Value, string Label)[] fontOptions =
        [("Small", "Small"), ("Medium", "Medium"), ("Large", "Large")];

    private static readonly (string Value, string Label)[] languageOptions =
        [("en", "English"), ("es", "Español"), ("fr", "Français"), ("de", "Deutsch"), ("ja", "日本語")];

    private string PreviewThemeClass => theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-system"
    };

    private string PreviewFontSize => fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string SelectedLanguageLabel =>
        languageOptions.FirstOrDefault(l => l.Value == language).Label ?? language;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !saving)
        {
            theme = Settings.Theme;
            fontSize = Settings.FontSize;
            language = Settings.Language;
            compactMode = Settings.CompactMode;
        }
    }

    private async Task Save()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Appearance settings saved!";
        }
        finally
        {
            saving = false;
        }
    }
}

