                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@saving">
        @if (saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool saving;
    private string? statusMessage;

    // Available channels for the mute list
    private readonly List<string> allChannels = ["general", "announcements", "engineering", "design", "marketing", "support"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !saving)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                emailNotifications, pushNotifications, weeklyDigest,
                mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            statusMessage = "Notification preferences saved!";
        }
        finally
        {
            saving = false;
        }
    }
}
