<div class="section-content">
    <h4 class="mb-4">Appearance</h4>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-header">Theme</div>
                <div class="card-body">
                    @foreach (var opt in themeOptions)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{opt.Value}")"
                                   value="@opt.Value"
                                   checked="@(theme == opt.Value)"
                                   @onchange="() => theme = opt.Value" />
                            <label class="form-check-label" for="@($"theme-{opt.Value}")">@opt.Label</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header">Font Size</div>
                <div class="card-body">
                    @foreach (var opt in fontOptions)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"font-{opt.Value}")"
                                   value="@opt.Value"
                                   checked="@(fontSize == opt.Value)"
                                   @onchange="() => fontSize = opt.Value" />
                            <label class="form-check-label" for="@($"font-{opt.Value}")">@opt.Label</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header">Language</div>
                <div class="card-body">
                    <select class="form-select" @bind="language">
                        @foreach (var lang in languageOptions)
                        {
                            <option value="@lang.Value">@lang.Label</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@saving">
                @if (saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-6">
            <div class="card">
                <div class="card-header">Live Preview</div>
                <div class="card-body preview-area @PreviewThemeClass"
                     style="font-size: @PreviewFontSize; padding: @(compactMode ? "0.5rem" : "1.25rem");">
                    <h5 style="margin-bottom: @(compactMode ? "0.25rem" : "0.75rem")">Preview Heading</h5>
                    <p style="margin-bottom: @(compactMode ? "0.25rem" : "0.75rem")">
                        This is a sample paragraph showing how your selected settings will look.
                        The current theme is <strong>@theme</strong> with <strong>@fontSize</strong> font.
                    </p>
                    <div class="d-flex gap-2" style="margin-bottom: @(compactMode ? "0.25rem" : "0.75rem")">
                        <button class="btn btn-primary btn-sm">Primary</button>
                        <button class="btn btn-outline-secondary btn-sm">Secondary</button>
                    </div>
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" checked disabled />
                        <label class="form-check-label">Sample checkbox</label>
                    </div>
                    <p class="text-muted small mt-2 mb-0">Language: @SelectedLanguageLabel</p>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string theme = "System";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private bool saving;
    private string? statusMessage;

    private static readonly (string Value, string Label)[] themeOptions =
        [("Light", "Light"), ("Dark", "Dark"), ("System", "System")];

    private static readonly (string Value, string Label)[] fontOptions =
        [("Small", "Small"), ("Medium", "Medium"), ("Large", "Large")];

    private static readonly (string Value, string Label)[] languageOptions =
        [("en", "English"), ("es", "Español"), ("fr", "Français"), ("de", "Deutsch"), ("ja", "日本語")];

    private string PreviewThemeClass => theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-system"
    };

    private string PreviewFontSize => fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string SelectedLanguageLabel =>
        languageOptions.FirstOrDefault(l => l.Value == language).Label ?? language;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !saving)
        {
            theme = Settings.Theme;
            fontSize = Settings.FontSize;
            language = Settings.Language;
            compactMode = Settings.CompactMode;
        }
    }

    private async Task Save()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Appearance settings saved!";
        }
        finally
        {
            saving = false;
        }
    }
}
