@namespace sv_5117f83b204c47e0925b9d7c1f6f89c0.Components.Settings

<div class="section-content">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in your browser</div>
                </label>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">Muted Channels</div>
        <div class="card-body">
            @if (allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@saving">
        @if (saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool saving;
    private string? statusMessage;

    // Available channels for the mute list
    private readonly List<string> allChannels = ["general", "announcements", "engineering", "design", "marketing", "support"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !saving)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                emailNotifications, pushNotifications, weeklyDigest,
                mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            statusMessage = "Notification preferences saved!";
        }
        finally
        {
            saving = false;
        }
    }
}

