@page "/settings"
@using sv_5117f83b204c47e0925b9d7c1f6f89c0.Components.Settings
@using sv_5117f83b204c47e0925b9d7c1f6f89c0.Models
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@activeSection" OnSectionChanged="SetSection" />

    <main class="settings-main">
        @if (loading)
        {
            <div class="d-flex justify-content-center align-items-center h-100">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (!string.IsNullOrEmpty(loadError))
        {
            <div class="alert alert-danger m-4">
                <strong>Error:</strong> @loadError
                <button class="btn btn-link" @onclick="LoadSectionData">Retry</button>
            </div>
        }
        else
        {
            @switch (activeSection)
            {
                case "profile":
                    <ProfileSection Profile="@profile" OnSave="SaveProfile" />
                    break;
                case "notifications":
                    <NotificationsSection Prefs="@notificationPrefs" OnSave="SaveNotifications" />
                    break;
                case "security":
                    <SecuritySection Security="@securitySettings"
                                     OnChangePassword="ChangePassword"
                                     OnRevokeSession="RevokeSession" />
                    break;
                case "appearance":
                    <AppearanceSection Settings="@appearanceSettings" OnSave="SaveAppearance" />
                    break;
            }
        }
    </main>
</div>

@code {
    private string activeSection = "profile";
    private bool loading = true;
    private string? loadError;

    private UserProfile? profile;
    private NotificationPrefs? notificationPrefs;
    private SecuritySettings? securitySettings;
    private AppearanceSettings? appearanceSettings;

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData();
    }

    private async Task SetSection(string section)
    {
        activeSection = section;
        await LoadSectionData();
    }

    private async Task LoadSectionData()
    {
        loading = true;
        loadError = null;
        try
        {
            switch (activeSection)
            {
                case "profile":
                    profile = await SettingsService.GetProfileAsync();
                    break;
                case "notifications":
                    notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
                    break;
                case "security":
                    securitySettings = await SettingsService.GetSecuritySettingsAsync();
                    break;
                case "appearance":
                    appearanceSettings = await SettingsService.GetAppearanceAsync();
                    break;
            }
        }
        catch (Exception ex)
        {
            loadError = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task SaveProfile(UserProfile updated)
    {
        await SettingsService.SaveProfileAsync(updated);
        profile = updated;
    }

    private async Task SaveNotifications(NotificationPrefs updated)
    {
        await SettingsService.SaveNotificationPrefsAsync(updated);
        notificationPrefs = updated;
    }

    private async Task ChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearance(AppearanceSettings updated)
    {
        await SettingsService.SaveAppearanceAsync(updated);
        appearanceSettings = updated;
    }
}

